// Validate and extract payload from SOC Triage Dashboard
const body = $input.first().json.body;

if (!body.logs || !Array.isArray(body.logs)) {
  throw new Error('Invalid payload: missing logs array');
}

// Build correlation summary
const ipMap = {};
for (const log of body.logs) {
  const ip = log.src_ip || 'unknown';
  if (!ipMap[ip]) ipMap[ip] = { sources: new Set(), actions: [], ports: [] };
  ipMap[ip].sources.add(log.source);
  if (log.action) ipMap[ip].actions.push(log.action);
  if (log.dst_port) ipMap[ip].ports.push(log.dst_port);
}

// Build prompt context
const correlationLines = Object.entries(ipMap).map(([ip, data]) => {
  const sources = [...data.sources].join(', ');
  const actions = data.actions.join(', ') || 'unknown';
  const ports = [...new Set(data.ports)].join(', ') || 'N/A';
  return `- IP: ${ip} | Sources: ${sources} | Actions: ${actions} | Ports: ${ports}`;
}).join('\n');

const logDetails = body.logs.map((l, i) => {
  return `[Event ${i+1}] Source: ${l.source} | Action: ${l.action || 'unknown'} | SrcIP: ${l.src_ip} | DstPort: ${l.dst_port || 'N/A'}\nLog: ${JSON.stringify(l.raw_log, null, 2)}`;
}).join('\n\n---\n\n');

const prompt = `You are an expert SOC analyst. Analyze these security logs and return a JSON threat report.

## IP CORRELATION SUMMARY\n${correlationLines}\n\n## EVENTS (${body.logs.length} total)\n${logDetails}\n\n${body.additionalContext ? `## ANALYST NOTES\n${body.additionalContext}\n\n` : ''}Return ONLY valid JSON (no markdown):\n{\n  "summary": "detailed 3-5 paragraph narrative",\n  "severity": "critical|high|medium|low|informational",\n  "iocs": ["list of IOCs"],\n  "recommendations": ["actionable steps"],\n  "attackVector": "description or null",\n  "affectedSystems": ["hostname/IP"],\n  "mitreAttackTechniques": ["T1078 - Valid Accounts", ...]\n}`;

return [{ json: { prompt, sessionId: body.sessionId, logCount: body.logs.length } }];

// Parse Gemini response and extract JSON
const geminiResponse = $input.first().json;
const candidates = geminiResponse.candidates;

if (!candidates || candidates.length === 0) {
  throw new Error('Gemini returned no candidates');
}

const text = candidates[0].content.parts[0].text.trim();

// Try to extract JSON from response
let parsed;
try {
  parsed = JSON.parse(text);
} catch {
  const match = text.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('Could not parse AI response as JSON');
  parsed = JSON.parse(match[0]);
}

// Normalize and validate fields
const validSeverities = ['critical', 'high', 'medium', 'low', 'informational'];
const severity = validSeverities.includes(parsed.severity) ? parsed.severity : 'informational';

return [{
  json: {
    summary: String(parsed.summary || 'Analysis complete'),
    severity,
    iocs: Array.isArray(parsed.iocs) ? parsed.iocs : [],
    recommendations: Array.isArray(parsed.recommendations) ? parsed.recommendations : [],
    attackVector: parsed.attackVector || null,
    affectedSystems: Array.isArray(parsed.affectedSystems) ? parsed.affectedSystems : [],
    mitreAttackTechniques: Array.isArray(parsed.mitreAttackTechniques) ? parsed.mitreAttackTechniques : [],
    executionId: `n8n-${Date.now()}`
  }
}];

// Handle errors gracefully
const error = $input.first().json.error || 'Unknown error';
return [{
  json: {
    summary: `Analysis failed: ${error}. Please check logs and retry.`,
    severity: 'informational',
    iocs: [],
    recommendations: ['Review n8n workflow logs for error details', 'Verify GEMINI_API_KEY is set in n8n environment'],
    attackVector: null,
    affectedSystems: [],
    mitreAttackTechniques: [],
    executionId: `n8n-error-${Date.now()}`
  }
}];
